import { useActionState } from 'react';
import { useFormStatus } from 'react-dom';
import type { ComponentProps } from 'react';

/* ------------------------------------------------------------------ */
/*  Types                                                             */
/* ------------------------------------------------------------------ */

export type SyncState = {
  success: boolean;
  message: string;
};

type SyncAction = (
  prevState: SyncState | null,
  formData: FormData
) => Promise<SyncState>;

/* ------------------------------------------------------------------ */
/*  Submit button – reads pending state from the nearest <form>        */
/* ------------------------------------------------------------------ */

function SubmitButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      className={
        'sync-btn' +
        (pending ? ' sync-btn--pending' : '')
      }
    >
      {pending ? '⏳ Syncing…' : '↻  Sync Latest Catalog'}
    </button>
  );
}

/* ------------------------------------------------------------------ */
/*  SyncForm                                                          */
/* ------------------------------------------------------------------ */

type SyncFormProps = {
  action: SyncAction;
} & Omit<ComponentProps<'form'>, 'action'>;

export function SyncForm({ action, ...formProps }: SyncFormProps) {
  const [state, formAction] = useActionState(action, null);

  return (
    <form action={formAction} {...formProps}>
      <SubmitButton />

      {state?.success === true && (
        <p className="sync-feedback sync-feedback--ok">{state.message}</p>
      )}
      {state?.success === false && (
        <p className="sync-feedback sync-feedback--err" role="alert">
          {state.message || 'Sync failed. Please try again.'}
        </p>
      )}
    </form>
  );
}
"}

