import type { Product } from '@/types/product';

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const statusLabel: Record<Product['status'], string> = {
  active: 'Active',
  inactive: 'Inactive',
  discontinued: 'Discontinued',
};

const statusClass: Record<Product['status'], string> = {
  active: 'badge badge--active',
  inactive: 'badge badge--inactive',
  discontinued: 'badge badge--discontinued',
};

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

function formatTimestamp(iso: string): string {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(iso));
}

/* ------------------------------------------------------------------ */
/*  Empty state                                                        */
/* ------------------------------------------------------------------ */

function EmptyState() {
  return (
    <div className="empty-state">
      <p>No products found in the catalog.</p>
      <p className="empty-state--hint">
        Try triggering a <strong>Sync Latest Catalog</strong> to pull
        product data from the upstream ERP/PIM.
      </p>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Table                                                              */
/* ------------------------------------------------------------------ */

type CatalogTableProps = {
  products: Product[];
};

export function CatalogTable({ products }: CatalogTableProps) {
  if (products.length === 0) {
    return <EmptyState />;
  }

  return (
    <div className="table-wrapper">
      <table className="catalog-table">
        <thead>
          <tr>
            <th>SKU</th>
            <th>Name</th>
            <th>Price</th>
            <th>Inventory</th>
            <th>Status</th>
            <th>Last Synced</th>
          </tr>
        </thead>
        <tbody>
          {products.map((p) => (
            <tr key={p.id}>
              <td className="cell-sku">{p.sku}</td>
              <td>{p.name}</td>
              <td className="cell-price">{formatCurrency(p.price)}</td>
              <td className="cell-inventory">
                {p.inventory === 0 ? (
                  <span className="no-stock">Out of stock</span>
                ) : (
                  p.inventory
                )}
              </td>
              <td>
                <span className={statusClass[p.status]}>
                  {statusLabel[p.status]}
                </span>
              </td>
              <td className="cell-timestamp">{formatTimestamp(p.lastSyncedAt)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
