import { after } from 'next/server';
import { getCachedProducts } from '@/lib/products';
import { performCatalogSync } from '@/lib/sync';
import { CatalogTable } from '@/components/admin/catalog-table';
import { SyncForm } from '@/components/admin/sync-form';
import type { SyncState } from '@/components/admin/sync-form';

/* ------------------------------------------------------------------ */
/*  Metadata                                                           */
/* ------------------------------------------------------------------ */

export const metadata = {
  title: 'Catalog — Admin',
};

/* ------------------------------------------------------------------ */
/*  Inline Server Action — sync trigger                                */
/* ------------------------------------------------------------------ */

/**
 * Triggered by the "Sync Latest Catalog" form submission.
 *
 * Design decisions
 * ----------------
 * 1. **Fire-and-forget via `after()`** — the action returns immediately
 *    so the admin can keep browsing while the sync runs in the background.
 *    Product data is briefly stale, which is acceptable for the admin use
 *    case (operators prefer a responsive UI over blocking on fresh data).
 *
 * 2. **Tag-based cache invalidation** — once the sync completes, the
 *    `"products"` cache tag is fully expired. Any subsequent page render
 *    that reads through `getCachedProducts` (wrapped with `unstable_cache`
 *    and tagged `"products"`) will fetch fresh data from the DB.
 *
 * 3. **Eventual consistency** — because all catalog views use the same
 *    cache tag, invalidating `"products"` guarantees consistency across
 *    the entire admin surface once the cache is repopulated.
 */
async function syncCatalog(
  _prevState: SyncState | null,
  _formData: FormData
): Promise<SyncState> {
  'use server';

  try {
    // Schedule the sync to run after the response is sent.
    // The admin sees the success message immediately and can continue
    // working. The product list may be briefly stale.
    after(async () => {
      await performCatalogSync();
      // Fully expire all cache entries tagged "products" so the next
      // page load fetches fresh data from the DB.
      revalidateTag('products', 'max');
    });

    return {
      success: true,
      message:
        'Catalog sync started — changes will appear across all catalog views shortly.',
    };
  } catch (err) {
    console.error('Catalog sync failed:', err);
    return {
      success: false,
      message:
        err instanceof Error
          ? err.message
          : 'An unexpected error occurred while syncing the catalog.',
    };
  }
}

/* ------------------------------------------------------------------ */
/*  Page component                                                     */
/* ------------------------------------------------------------------ */

export default async function CatalogPage() {
  const products = await getCachedProducts();

  return (
    <main className="catalog-page">
      <header className="catalog-header">
        <div>
          <h1>Product Catalog</h1>
          <p className="catalog-subtitle">
            {products.length} product{products.length !== 1 ? 's' : ''} —
            <span className="catalog-note">
              {' '}prices & inventory are cached; run a sync to refresh
            </span>
          </p>
        </div>

        <SyncForm action={syncCatalog} />
      </header>

      <CatalogTable products={products} />
    </main>
  );
}
"}

